  9→const (
 10→	commonAppURL = "https://www.commonapp.org/explore"
 11→
 12→	// commonAppMinExpected is the minimum number of institutions we expect.
 13→	// Common App has ~1100 members; fewer suggests a scraping failure.
 14→	commonAppMinExpected = 900
 15→)
 16→
 17→// extractJS is a self-contained JavaScript expression that fetches the Common
 18→// App explore page and extracts institution names. Because the Browser
 19→// implementation runs Navigate and EvalStrings in separate tabs, this JS must
 20→// fetch the page itself rather than relying on prior navigation state.
 21→//
 22→// Strategy: fetch the explore page HTML, parse the __NEXT_DATA__ JSON payload
 23→// that Next.js embeds in the page, and extract school names from it. Falls back
 24→// to trying known API endpoint patterns.
 25→const extractJS = `(async () => {
 26→	// Strategy 1: Fetch explore page and parse __NEXT_DATA__ (Next.js embed).
 27→	try {
 28→		const resp = await fetch("https://www.commonapp.org/explore");
 29→		const html = await resp.text();
 30→		const match = html.match(/<script id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
 31→		if (match) {
 32→			const data = JSON.parse(match[1]);
 33→			// Walk the props tree looking for an array of school objects.
 34→			const find = (obj) => {
 35→				if (!obj || typeof obj !== 'object') return null;
 36→				if (Array.isArray(obj) && obj.length > 100 && obj[0] && (obj[0].name || obj[0].schoolName || obj[0].collegeName || obj[0].institution_name)) {
 37→					const key = obj[0].name ? 'name' : obj[0].schoolName ? 'schoolName' : obj[0].collegeName ? 'collegeName' : 'institution_name';
 38→					return obj.map(s => s[key]).filter(Boolean);
 39→				}
 40→				for (const v of Object.values(obj)) {
 41→					const r = find(v);
 42→					if (r) return r;
 43→				}
 44→				return null;
 45→			};
 46→			const names = find(data);
 47→			if (names && names.length > 100) return names;
 48→		}
 49→	} catch (e) { /* continue to next strategy */ }
 50→
 51→	// Strategy 2: Try common API endpoints.
 52→	const endpoints = [
 53→		"https://www.commonapp.org/api/explore",
 54→		"https://www.commonapp.org/api/colleges",
 55→		"https://www.commonapp.org/api/explore/colleges",
 56→		"https://www.commonapp.org/api/search",
 57→	];
 58→	for (const ep of endpoints) {
 59→		try {
 60→			const resp = await fetch(ep);
 61→			if (!resp.ok) continue;
 62→			const data = await resp.json();
 63→			const arr = Array.isArray(data) ? data : (data.results || data.colleges || data.schools || data.data || []);
 64→			if (arr.length > 100) {
 65→				return arr.map(s => s.name || s.schoolName || s.collegeName || s.title || "").filter(Boolean);
 66→			}
 67→		} catch (e) { /* try next */ }
 68→	}
 69→
 70→	// Strategy 3: Fetch the page and try to extract from rendered markup patterns.
 71→	try {
 72→		const resp = await fetch("https://www.commonapp.org/explore");
 73→		const html = await resp.text();
 74→		// Look for JSON data embedded in script tags (non-__NEXT_DATA__).
 75→		const scripts = [...html.matchAll(/<script[^>]*>([\s\S]*?)<\/script>/g)];
 76→		for (const [, body] of scripts) {
 77→			if (body.length < 500) continue;
 78→			try {
 79→				const data = JSON.parse(body);
 80→				const find = (obj, depth) => {
 81→					if (depth > 5 || !obj || typeof obj !== 'object') return null;
 82→					if (Array.isArray(obj) && obj.length > 100 && obj[0] && typeof obj[0] === 'object') {
 83→						for (const key of ['name', 'schoolName', 'collegeName', 'institution_name', 'title']) {
 84→							if (obj[0][key]) return obj.map(s => s[key]).filter(Boolean);
 85→						}
 86→					}
 87→					for (const v of Object.values(obj)) {
 88→						const r = find(v, depth + 1);
 89→						if (r) return r;
 90→					}
 91→					return null;
 92→				};
 93→				const names = find(data, 0);
 94→				if (names && names.length > 100) return names;
 95→			} catch (e) { /* not JSON, skip */ }
 96→		}
 97→	} catch (e) { /* give up */ }
 98→
 99→	return [];
100→})()`
