102→// commonApp implements Extractor for the Common App explore page.
103→type commonApp struct{}
104→
105→// NewCommonApp returns an Extractor that scrapes Common App member institutions
106→// from commonapp.org/explore.
107→func NewCommonApp() Extractor {
108→	return &commonApp{}
109→}
