111→func (c *commonApp) Key() string   { return KeyCommon }
112→func (c *commonApp) Label() string { return "Common App" }
113→
114→func (c *commonApp) Extract(ctx context.Context, browser Browser) ([]string, error) {
115→	// Navigate to warm up the browser session (cookies, etc.).
116→	// The tab closes after Navigate returns, but cookies persist across tabs.
117→	if err := browser.Navigate(ctx, commonAppURL); err != nil {
118→		return nil, fmt.Errorf("platform: commonapp: navigate: %w", err)
119→	}
120→
121→	// Run self-contained JS that fetches and parses the data.
122→	names, err := browser.EvalStrings(ctx, extractJS)
123→	if err != nil {
124→		return nil, fmt.Errorf("platform: commonapp: eval: %w", err)
125→	}
126→
127→	unique := deduplicate(names)
128→	if len(unique) < commonAppMinExpected {
129→		return unique, fmt.Errorf("platform: commonapp: got %d names, expected at least %d", len(unique), commonAppMinExpected)
130→	}
131→
132→	return unique, nil
133→}
134→
135→// deduplicate removes empty strings, trims whitespace, and removes duplicates
136→// while preserving order.
137→func deduplicate(names []string) []string {
138→	seen := make(map[string]bool, len(names))
139→	result := make([]string, 0, len(names))
140→	for _, name := range names {
141→		name = strings.TrimSpace(name)
142→		if name == "" || seen[name] {
143→			continue
144→		}
145→		seen[name] = true
146→		result = append(result, name)
147→	}
148→	return result
149→}
